<div class="form-group"><div class="row"><label class="col-md-3"><?php echo app_lang("gd_type"); ?></label><div class="col-md-3"><select name="booking_type" class="form-control"><?php foreach($types as $v){ ?><option value="<?php echo $e($v); ?>"<?php echo ($model_info->booking_type??"internal")===$v?" selected":""; ?>><?php echo app_lang("gd_booking_type_".$v); ?></option><?php } ?></select></div><label class="col-md-3"><?php echo app_lang("gd_status"); ?></label><div class="col-md-3"><?php if($id){ ?><input class="form-control" value="<?php echo app_lang("gd_booking_status_".$model_info->status); ?>" disabled><?php }else{ ?><select name="status" id="gd-booking-status" class="form-control"><?php foreach($initial_statuses as $v){ ?><option value="<?php echo $v; ?>"><?php echo app_lang("gd_booking_status_".$v); ?></option><?php } ?></select><?php } ?></div></div></div>
<div class="form-group"><div class="row"><label class="col-md-3"><?php echo app_lang("gd_title"); ?></label><div class="col-md-9"><input name="title" class="form-control" maxlength="180" required value="<?php echo $e($model_info->title??""); ?>"></div></div></div>
<div class="form-group"><div class="row"><label class="col-md-3"><?php echo app_lang("gd_customer"); ?></label><div class="col-md-3"><select name="customer_account_id" id="gd-booking-customer" class="form-control"><option value=""></option><?php foreach($accounts as $a){ ?><option value="<?php echo (int)$a["id"]; ?>"<?php echo (int)($model_info->customer_account_id??0)===(int)$a["id"]?" selected":""; ?>><?php echo $e($a["display_name"]); ?></option><?php } ?></select></div><label class="col-md-3"><?php echo app_lang("gd_contact"); ?></label><div class="col-md-3"><select name="contact_person_id" id="gd-booking-contact" class="form-control"><option value=""></option><?php foreach($contacts as $p){ ?><option value="<?php echo (int)$p["id"]; ?>"<?php echo (int)($model_info->contact_person_id??0)===(int)$p["id"]?" selected":""; ?>><?php echo $e($p["full_name"]); ?></option><?php } ?></select></div></div></div>
<div class="form-group"><div class="row"><label class="col-md-3"><?php echo app_lang("gd_starts_at"); ?></label><div class="col-md-3"><input type="datetime-local" name="starts_at_local" class="form-control" required value="<?php echo $e($starts_local); ?>"></div><label class="col-md-3"><?php echo app_lang("gd_ends_at"); ?></label><div class="col-md-3"><input type="datetime-local" name="ends_at_local" class="form-control" required value="<?php echo $e($ends_local); ?>"></div></div><small class="text-muted"><?php echo app_lang("gd_unit_timezone").": ".$e($timezone); ?></small></div>
