<div class="form-group"><label><?php echo app_lang("gd_resources_and_buffers"); ?></label><div class="table-responsive"><table class="table table-sm"><thead><tr><th></th><th><?php echo app_lang("gd_resource"); ?></th><th><?php echo app_lang("gd_buffer_before"); ?></th><th><?php echo app_lang("gd_buffer_after"); ?></th></tr></thead><tbody><?php foreach($resources as $r){$current=$selected[(int)$r["id"]]??null; ?><tr><td><input type="checkbox" name="resources[<?php echo (int)$r["id"]; ?>][selected]" value="1"<?php echo $current?" checked":""; ?>></td><td><?php echo $e($r["code"]." — ".$r["name"]); ?></td><td><input type="number" min="0" name="resources[<?php echo (int)$r["id"]; ?>][buffer_before_minutes]" class="form-control" value="<?php echo (int)($current->buffer_before_minutes??0); ?>"></td><td><input type="number" min="0" name="resources[<?php echo (int)$r["id"]; ?>][buffer_after_minutes]" class="form-control" value="<?php echo (int)($current->buffer_after_minutes??0); ?>"></td></tr><?php } ?></tbody></table></div></div>
<div class="form-group"><label><?php echo app_lang("gd_notes"); ?></label><textarea name="notes" class="form-control" rows="2"><?php echo $e($model_info->notes??""); ?></textarea></div><div class="form-group"><label><?php echo app_lang("gd_metadata_json"); ?></label><textarea name="metadata" class="form-control" rows="2"><?php echo $e($model_info->metadata??""); ?></textarea></div><div id="gd-booking-check-result" class="mb10"></div>
</div></div><div class="modal-footer"><button type="button" id="gd-booking-check" class="btn btn-info"><?php echo app_lang("gd_check_availability"); ?></button><button type="button" class="btn btn-default" data-bs-dismiss="modal"><?php echo app_lang("close"); ?></button><button type="submit" class="btn btn-primary"><?php echo app_lang("save"); ?></button></div><?php echo form_close(); ?>
<script>$(document).ready(function(){var f=$("#gd-booking-form"),customer=$("#gd-booking-customer"),contact=$("#gd-booking-contact");f.appForm({onSuccess:function(r){location.href='<?php echo_uri("grupo_donato/bookings/view/"); ?>'+r.id;}});customer.select2({placeholder:'-',allowClear:true,ajax:{url:'<?php echo_uri($customer_options_uri); ?>',type:'POST',dataType:'json',delay:250,data:function(p){return {q:p.term||''};},processResults:function(d){return d;}}}).on('change',function(){contact.val(null).trigger('change');});contact.select2({placeholder:'-',allowClear:true,ajax:{url:'<?php echo_uri($contact_options_uri); ?>',type:'POST',dataType:'json',delay:250,data:function(p){return {q:p.term||'',customer_account_id:customer.val()};},processResults:function(d){return d;}}});function hold(){$('.gd-hold-row').toggle(!<?php echo $id?"true":"false"; ?>&&$('#gd-booking-status').val()==='hold');}$('#gd-booking-status').on('change',hold);hold();$('#gd-booking-check').on('click',function(){$.post('<?php echo_uri($booking_check_uri); ?>',f.serialize()).done(function(r){$('#gd-booking-check-result').html(r.success&&r.data.available?'<span class="text-success"><?php echo addslashes(app_lang("gd_available")); ?></span>':'<span class="text-danger">'+(r.message||'<?php echo addslashes(app_lang("gd_unavailable")); ?>')+'</span>');});});});</script>
